svg.script:
        
            function updateClock() {
                var now = new Date();
                var hours = now.getHours();
                var minutes = now.getMinutes();
                var seconds = now.getSeconds();

                var hourHand = document.getElementById("hour-hand");
                var minuteHand = document.getElementById("minute-hand");
                var secondHand = document.getElementById("second-hand");
                var digitalClock = document.getElementById("digital-clock");

                // Update hour hand
                hourHand.setAttribute("transform", "rotate(" + (hours * 30 + minutes * 0.5) + ")");

                // Update minute hand
                minuteHand.setAttribute("transform", "rotate(" + (minutes * 6) + ")");

                // Update second hand
                secondHand.setAttribute("transform", "rotate(" + (seconds * 6) + ")");

                // Update digital clock
                digitalClock.textContent = ("0" + hours).slice(-2) + ":" + ("0" + minutes).slice(-2) + ":" + ("0" + seconds).slice(-2);
            }

            // Update clock every second
            setInterval(updateClock, 1000);

            // Initial update to avoid delay
            updateClock();
